section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/qa-prioritization-rubric.json",
  "type": "object",
  "title": "QA Prioritization Rubric",
  "required": [
    "rubric_version",
    "tiers",
    "triage_decisions"
  ],
  "additionalProperties": false,
  "properties": {
    "rubric_version": {
      "type": "string",
      "minLength": 1,
      "description": "Semver."
    },
    "tiers": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "List of {tier, blast_radius, frequency_floor, workaround_effect, sla_first_response_h, sla_resolution_h}."
    },
    "triage_decisions": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "Recent triages: {bug_id, tier, anchor_rule_id}."
    }
  }
}
